<div style="font-family:Inter,system-ui,sans-serif; padding:16px; background:#0b1020; color:#e5e7eb; border-radius:12px;">
  <h3 style="margin:0 0 6px; color:#f8fafc;">Interactive Periodic Table</h3>
  <p style="margin:0 0 14px; color:#94a3b8; font-size:13px;">Hover an element to see details. Click to pin selection.</p>

  <div id="info" style="background:#111827; border:1px solid #1f2937; border-radius:10px; padding:12px; margin-bottom:14px; min-height:70px;">
    <div style="font-size:12px; color:#94a3b8;">Selected Element</div>
    <div id="name" style="font-size:20px; font-weight:700; color:#f8fafc;">Hydrogen (H)</div>
    <div id="meta" style="font-size:13px; color:#cbd5e1;">Atomic Number: 1 • Category: Nonmetal • Atomic Mass: 1.008</div>
  </div>

<div id="table" style="
    display:grid;
    grid-template-columns:repeat(18, minmax(34px, 1fr));
    gap:6px;
    overflow:auto;
    padding:4px;
    background:#0f172a;
    border-radius:10px;
    border:1px solid #1e293b;
  "></div>

<div style="margin-top:12px; display:flex; flex-wrap:wrap; gap:8px; font-size:12px;">
    <span style="padding:4px 8px; border-radius:999px; background:#1d4ed8;">Alkali metal</span>
    <span style="padding:4px 8px; border-radius:999px; background:#2563eb;">Alkaline earth</span>
    <span style="padding:4px 8px; border-radius:999px; background:#0ea5e9;">Transition metal</span>
    <span style="padding:4px 8px; border-radius:999px; background:#14b8a6;">Post-transition</span>
    <span style="padding:4px 8px; border-radius:999px; background:#22c55e;">Metalloid</span>
    <span style="padding:4px 8px; border-radius:999px; background:#84cc16;">Nonmetal</span>
    <span style="padding:4px 8px; border-radius:999px; background:#f59e0b;">Halogen</span>
    <span style="padding:4px 8px; border-radius:999px; background:#ef4444;">Noble gas</span>
    <span style="padding:4px 8px; border-radius:999px; background:#a855f7;">Lanthanide</span>
    <span style="padding:4px 8px; border-radius:999px; background:#d946ef;">Actinide</span>
  </div>
</div>

<script>
const colors = {
  "alkali metal":"#1d4ed8","alkaline earth metal":"#2563eb","transition metal":"#0ea5e9",
  "post-transition metal":"#14b8a6","metalloid":"#22c55e","nonmetal":"#84cc16",
  "halogen":"#f59e0b","noble gas":"#ef4444","lanthanide":"#a855f7","actinide":"#d946ef","unknown":"#64748b"
};

const elements = [
  // period 1
  {n:1,s:"H",name:"Hydrogen",m:1.008,c:"nonmetal",p:1,g:1},{n:2,s:"He",name:"Helium",m:4.0026,c:"noble gas",p:1,g:18},
  // period 2
  {n:3,s:"Li",name:"Lithium",m:6.94,c:"alkali metal",p:2,g:1},{n:4,s:"Be",name:"Beryllium",m:9.0122,c:"alkaline earth metal",p:2,g:2},
  {n:5,s:"B",name:"Boron",m:10.81,c:"metalloid",p:2,g:13},{n:6,s:"C",name:"Carbon",m:12.011,c:"nonmetal",p:2,g:14},
  {n:7,s:"N",name:"Nitrogen",m:14.007,c:"nonmetal",p:2,g:15},{n:8,s:"O",name:"Oxygen",m:15.999,c:"nonmetal",p:2,g:16},
  {n:9,s:"F",name:"Fluorine",m:18.998,c:"halogen",p:2,g:17},{n:10,s:"Ne",name:"Neon",m:20.180,c:"noble gas",p:2,g:18},
  // period 3
  {n:11,s:"Na",name:"Sodium",m:22.990,c:"alkali metal",p:3,g:1},{n:12,s:"Mg",name:"Magnesium",m:24.305,c:"alkaline earth metal",p:3,g:2},
  {n:13,s:"Al",name:"Aluminum",m:26.982,c:"post-transition metal",p:3,g:13},{n:14,s:"Si",name:"Silicon",m:28.085,c:"metalloid",p:3,g:14},
  {n:15,s:"P",name:"Phosphorus",m:30.974,c:"nonmetal",p:3,g:15},{n:16,s:"S",name:"Sulfur",m:32.06,c:"nonmetal",p:3,g:16},
  {n:17,s:"Cl",name:"Chlorine",m:35.45,c:"halogen",p:3,g:17},{n:18,s:"Ar",name:"Argon",m:39.948,c:"noble gas",p:3,g:18},
  // period 4
  {n:19,s:"K",name:"Potassium",m:39.098,c:"alkali metal",p:4,g:1},{n:20,s:"Ca",name:"Calcium",m:40.078,c:"alkaline earth metal",p:4,g:2},
  {n:21,s:"Sc",name:"Scandium",m:44.956,c:"transition metal",p:4,g:3},{n:22,s:"Ti",name:"Titanium",m:47.867,c:"transition metal",p:4,g:4},
  {n:23,s:"V",name:"Vanadium",m:50.942,c:"transition metal",p:4,g:5},{n:24,s:"Cr",name:"Chromium",m:51.996,c:"transition metal",p:4,g:6},
  {n:25,s:"Mn",name:"Manganese",m:54.938,c:"transition metal",p:4,g:7},{n:26,s:"Fe",name:"Iron",m:55.845,c:"transition metal",p:4,g:8},
  {n:27,s:"Co",name:"Cobalt",m:58.933,c:"transition metal",p:4,g:9},{n:28,s:"Ni",name:"Nickel",m:58.693,c:"transition metal",p:4,g:10},
  {n:29,s:"Cu",name:"Copper",m:63.546,c:"transition metal",p:4,g:11},{n:30,s:"Zn",name:"Zinc",m:65.38,c:"transition metal",p:4,g:12},
  {n:31,s:"Ga",name:"Gallium",m:69.723,c:"post-transition metal",p:4,g:13},{n:32,s:"Ge",name:"Germanium",m:72.630,c:"metalloid",p:4,g:14},
  {n:33,s:"As",name:"Arsenic",m:74.922,c:"metalloid",p:4,g:15},{n:34,s:"Se",name:"Selenium",m:78.971,c:"nonmetal",p:4,g:16},
  {n:35,s:"Br",name:"Bromine",m:79.904,c:"halogen",p:4,g:17},{n:36,s:"Kr",name:"Krypton",m:83.798,c:"noble gas",p:4,g:18}
];

const table = document.getElementById('table');
const nameEl = document.getElementById('name');
const metaEl = document.getElementById('meta');
let pinned = null;

function setInfo(el){
  nameEl.textContent = `${el.name} (${el.s})`;
  metaEl.textContent = `Atomic Number: ${el.n} • Category: ${el.c} • Atomic Mass: ${el.m}`;
}

for(let r=1;r<=7;r++){
  for(let c=1;c<=18;c++){
    const el = elements.find(x=>x.p===r && x.g===c);
    const cell = document.createElement('button');
    cell.style.cssText = `
      height:48px;border:none;border-radius:8px;cursor:pointer;color:white;
      font-size:12px;line-height:1.1;padding:2px;background:${el ? (colors[el.c]||colors.unknown) : "transparent"};
      opacity:${el?1:0.08};`;
    if(el){
      cell.innerHTML = `<div style="font-size:10px;opacity:.9">${el.n}</div><div style="font-weight:700">${el.s}</div>`;
      cell.title = `${el.name} (${el.s})`;
      cell.onmouseenter = ()=>{ if(!pinned) setInfo(el); };
      cell.onclick = ()=>{ pinned = el; setInfo(el); document.querySelectorAll('#table button').forEach(b=>b.style.outline='none'); cell.style.outline='2px solid #f8fafc'; };
    } else {
      cell.disabled = true;
    }
    table.appendChild(cell);
  }
}
setInfo(elements[0]);
</script>
